def _normalize_arrivals_for_c(arrivals_iter, H):
    norm = []
    for t, o, s in arrivals_iter:
        if s <= 0:
            continue
        eta = int(math.ceil(t))
        if eta < 1:
            eta = 1
        if eta > H:
            continue
        norm.append((eta, int(o), int(s)))
    norm.sort()
    return norm


def _build_arrival_buffer(norm_arrivals):
    n = len(norm_arrivals)
    buf = (_CArrival * n)()
    for i, (eta, o, s) in enumerate(norm_arrivals):
        buf[i].eta = eta
        buf[i].owner = o
        buf[i].ships = s
    return buf, n


def simulate_planet_timeline_full_c(planet_owner, planet_ships, planet_prod,
                                      arrivals, player, H):
    """Drop-in replacement for simulate_planet_timeline using C ext."""
    H = max(0, int(math.ceil(H)))
    norm = _normalize_arrivals_for_c(arrivals, H)
    buf, n = _build_arrival_buffer(norm)
    owner_arr = (ctypes.c_int * (H + 1))()
    ships_arr = (ctypes.c_double * (H + 1))()
    keep_needed = ctypes.c_int(0)
    min_owned = ctypes.c_int(0)
    first_enemy = ctypes.c_int(0)
    fall_turn = ctypes.c_int(0)
    holds_full = ctypes.c_int(0)
    _LIB.c_simulate_planet_timeline_full(
        int(planet_owner), int(planet_ships), int(planet_prod),
        buf, n, int(player), H,
        owner_arr, ships_arr,
        ctypes.byref(keep_needed),
        ctypes.byref(min_owned),
        ctypes.byref(first_enemy),
        ctypes.byref(fall_turn),
        ctypes.byref(holds_full),
    )
    fe = first_enemy.value
    ft = fall_turn.value
    return {
        "owner_at": list(owner_arr),
        "ships_at": list(ships_arr),
        "keep_needed": keep_needed.value,
        "min_owned": min_owned.value,
        "first_enemy": None if fe < 0 else fe,
        "fall_turn": None if ft < 0 else ft,
        "holds_full": bool(holds_full.value),
        "horizon": H,
    }

