def _ibr_enemy_time_for_step(world) -> float:
    """v6.9: derive IBR enemy mini-beam time from available overage."""
    base = _BS_IBR_TIME_ENEMY
    overage_per_step = max(0.0, (world.remaining_overage - _PHASE_A_RESERVE_FOR_B)) \
                        / max(1, world.remaining_steps)
    return base + overage_per_step * 0.5


