# Â§3  MATH HELPERS (Python)
# â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

def _fleet_speed(ships: int) -> float:
    if ships <= 1:
        return 1.0
    s = 1.0 + (_MAX_SPEED - 1.0) * (math.log(ships) / math.log(1000.0)) ** 1.5
    return s if s < _MAX_SPEED else _MAX_SPEED


def _min_ships_for_steps(d: float, T: int) -> int:
    if T <= 0:
        return 10**9
    ratio = d / T
    if ratio <= 1.0:
        return 1
    if ratio >= _MAX_SPEED:
        return 10**9
    return max(1, math.ceil(1000.0 ** (((ratio - 1.0) / (_MAX_SPEED - 1.0)) ** (2.0 / 3.0))))


def _pt_seg_dist_sq(px, py, vx, vy, wx, wy):
    dx, dy = wx - vx, wy - vy
    l2 = dx * dx + dy * dy
    if l2 == 0.0:
        ax, ay = px - vx, py - vy
        return ax * ax + ay * ay
    t = ((px - vx) * dx + (py - vy) * dy) / l2
    if t < 0.0:
        t = 0.0
    elif t > 1.0:
        t = 1.0
    qx = vx + t * dx - px
    qy = vy + t * dy - py
    return qx * qx + qy * qy


def _segment_blocked_exact(x1, y1, x2, y2, blockers) -> bool:
    SUN_R2 = SUN_RADIUS * SUN_RADIUS
    if _pt_seg_dist_sq(CENTER, CENTER, x1, y1, x2, y2) < SUN_R2:
        return True
    return any(_pt_seg_dist_sq(p.x, p.y, x1, y1, x2, y2) < p.radius * p.radius for p in blockers)


