# Â§4  SIMULAZIONE DI VOLO â€” Python fallback (used only for comet-path hops)
# â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

def _simulate_fleet_flight_py(start_x, start_y, angle, speed,
                               cur_step, max_steps,
                               pids, r2s, xs_2d, ys_2d, alive_until, exclude_idx):
    cos_a = math.cos(angle)
    sin_a = math.sin(angle)
    SUN_R2 = SUN_RADIUS * SUN_RADIUS
    fx, fy = start_x, start_y
    n = pids.shape[0]
    max_step_in_data = xs_2d.shape[1]

    for k in range(max_steps):
        old_x, old_y = fx, fy
        nx = fx + cos_a * speed
        ny = fy + sin_a * speed

        if nx < 0.0 or nx > BOARD_SIZE or ny < 0.0 or ny > BOARD_SIZE:
            return (3, k + 1, -1)
        if _pt_seg_dist_sq(CENTER, CENTER, old_x, old_y, nx, ny) < SUN_R2:
            return (2, k + 1, -1)

        abs_pre  = cur_step + k
        abs_post = abs_pre + 1

        if abs_pre < max_step_in_data:
            for i in range(n):
                if i == exclude_idx or abs_pre > alive_until[i]:
                    continue
                r2 = r2s[i]
                px = xs_2d[i, abs_pre]
                py = ys_2d[i, abs_pre]
                if _pt_seg_dist_sq(px, py, old_x, old_y, nx, ny) < r2:
                    return (0, k + 1, i)

        if abs_post < max_step_in_data:
            for i in range(n):
                if i == exclude_idx or abs_post > alive_until[i]:
                    continue
                r2   = r2s[i]
                px0  = xs_2d[i, abs_pre]
                py0  = ys_2d[i, abs_pre]
                px1  = xs_2d[i, abs_post]
                py1  = ys_2d[i, abs_post]
                if px0 == px1 and py0 == py1:
                    continue
                if _pt_seg_dist_sq(nx, ny, px0, py0, px1, py1) < r2:
                    return (1, k + 1, i)
        fx, fy = nx, ny

    return (4, max_steps, -1)


