# Â§5  WORLD MODEL
# â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

Planet = namedtuple("Planet", ["id", "owner", "x", "y", "radius", "ships", "production"])
Fleet  = namedtuple("Fleet",  ["id", "owner", "x", "y", "angle", "from_planet_id", "ships"])


def dist(x1, y1, x2, y2):
    return math.hypot(x1 - x2, y1 - y2)


def is_static_planet(p):
    return math.hypot(p.x - CENTER, p.y - CENTER) + p.radius >= ROTATION_RADIUS_LIMIT


def predict_target_position(target, turns, initial_by_id, ang_vel, comets, comet_ids):
    if target.id in comet_ids:
        for group in comets:
            pids = group.get("planet_ids", [])
            if target.id not in pids:
                continue
            idx   = pids.index(target.id)
            paths = group.get("paths", [])
            pi    = group.get("path_index", 0)
            if idx >= len(paths):
                return None
            path       = paths[idx]
            future_idx = pi + int(turns)
            if 0 <= future_idx < len(path):
                return path[future_idx][0], path[future_idx][1]
            return None
        return None
    init = initial_by_id.get(target.id)
    if init is None:
        return target.x, target.y
    r = math.hypot(init.x - CENTER, init.y - CENTER)
    if r + init.radius >= ROTATION_RADIUS_LIMIT:
        return target.x, target.y
    cur_ang = math.atan2(target.y - CENTER, target.x - CENTER)
    new_ang = cur_ang + ang_vel * turns
    return (CENTER + r * math.cos(new_ang), CENTER + r * math.sin(new_ang))


class WorldModel:
    def __init__(self, obs):
        self.player            = obs.get('player', 0)
        self.step              = obs.get('step', 0)
        _total                 = int(obs.get('num_steps', obs.get('total_steps', 200)))
        self.remaining_steps   = max(1, _total - self.step)
        self.remaining_overage = float(obs.get('remainingOverageTime', 60.0))
        self.ang_vel           = obs.get('angular_velocity', 0.0)
        self.planets           = [Planet(*p) for p in obs.get('planets', [])]
        self.fleets            = [Fleet(*f)  for f in obs.get('fleets', [])]
        self.initial_by_id     = {p[0]: Planet(*p) for p in obs.get('initial_planets', [])}
        self.comets            = obs.get('comets', []) or []
        self.comet_ids         = set(obs.get('comet_planet_ids', []) or [])
        self.planet_by_id      = {p.id: p for p in self.planets}
        self.my_planets        = [p for p in self.planets if p.owner == self.player]
        self.enemy_planets     = [p for p in self.planets if p.owner != self.player and p.owner != -1]
        self.neutral_planets   = [p for p in self.planets if p.owner == -1]
        self.my_fleets         = [f for f in self.fleets if f.owner == self.player]
        self.enemy_fleets      = [f for f in self.fleets if f.owner != self.player]


# â”€â”€ Module-level mutable state (shared across phase_a, phase_b, main) â”€â”€â”€â”€â”€â”€â”€â”€
# These objects are MUTATED in place (dict.clear/update, list.append, etc.) so
# Scalar attributes (_AGENT_STEP, _WARMED_UP) are read/written as `engine.X`
_SAVED_INIT_DATA: dict = {}
_match_cache: dict = {}
_my_fleet_log: list = []
_pending_my_launches: list = []
_ENEMY_PLAN_ARRAYS: dict = {}
_OUR_PLAN_ARRAYS: dict   = {}
_g_orbital_forecast: dict = {}
_AGENT_STEP: int = 0
_WARMED_UP:  bool = False


def build_world(obs):
    """Build a WorldModel from obs, restoring cached initial_by_id if needed.
    Mutates module-level _SAVED_INIT_DATA on first call with planets data.
    """
    global _SAVED_INIT_DATA
    w = WorldModel(obs)
    if w.initial_by_id:
        _SAVED_INIT_DATA = dict(w.initial_by_id)
    elif _SAVED_INIT_DATA:
        w.initial_by_id = _SAVED_INIT_DATA
    return w


def _planet_list_by_idx(world, csr) -> list:
    return [world.planet_by_id.get(pid) for pid in csr['idx_to_pid']]


def _ships_array(world, csr) -> np.ndarray:
    return np.array(
        [float(world.planet_by_id[pid].ships) if pid in world.planet_by_id else 0.0
         for pid in csr['idx_to_pid']],
        dtype=np.float64,
    )


def _owners_array(world, csr) -> np.ndarray:
    return np.array(
        [int(world.planet_by_id[pid].owner) if pid in world.planet_by_id else -1
         for pid in csr['idx_to_pid']],
        dtype=np.int32,
    )


