# Engine constants for the exact fleet-flight simulator (v56).

HORIZON = 200       # max steps to simulate per timeline (matches v3.3)
INTERCEPT_TOLERANCE = 2  # turns
_SUN_R2 = SUN_RADIUS * SUN_RADIUS


def _fleet_speed(ships: float) -> float:
    """Mirror of _engine.fleet_speed for use without circular import risk."""
    if ships <= 1:
        return 1.0
    ratio = math.log(max(1, ships)) / math.log(1000.0)
    ratio = max(0.0, min(1.0, ratio))
    return 1.0 + (_MAX_SPEED - 1.0) * (ratio ** 1.5)


def normalize_arrivals(arrivals, horizon: int):
    """v3.3:454-464. Round ETAs to next integer â‰¥ 1, filter out >horizon and
    ships<=0. Return list sorted by eta ascending."""
    events = []
    for turns, owner, ships in arrivals:
        if ships <= 0:
            continue
        eta = max(1, int(math.ceil(turns)))
        if eta > horizon:
            continue
        events.append((eta, owner, int(ships)))
    events.sort(key=lambda item: item[0])
    return events


def resolve_arrival_event(owner: int, garrison: float, arrivals):
    """v3.3:420-452. Multi-faction arrival resolution at a single turn.

    Rules:
    - Group incoming ships by attacker_owner.
    - Top fighter wins by (top_ships - second_ships) survivors.
    - If top == second, no winner (becomes neutral with 0 ships).
    - Survivors then fight the garrison normally.
    """
    by_owner = {}
    for _, attacker_owner, ships in arrivals:
        by_owner[attacker_owner] = by_owner.get(attacker_owner, 0) + ships

    if not by_owner:
        return owner, max(0.0, garrison)

    sorted_players = sorted(by_owner.items(), key=lambda item: item[1], reverse=True)
    top_owner, top_ships = sorted_players[0]

    if len(sorted_players) > 1:
        second_ships = sorted_players[1][1]
        if top_ships == second_ships:
            survivor_owner = -1
            survivor_ships = 0
        else:
            survivor_owner = top_owner
            survivor_ships = top_ships - second_ships
    else:
        survivor_owner = top_owner
        survivor_ships = top_ships

    if survivor_ships <= 0:
        return owner, max(0.0, garrison)

    if owner == survivor_owner:
        return owner, garrison + survivor_ships

    garrison -= survivor_ships
    if garrison < 0:
        return survivor_owner, -garrison
    return owner, garrison


def _owner_ships_at_T(planet, arrivals, T):
    """v7.21 â€” Fast single-point query: returns (owner, ships) at turn T,
    bit-equivalent to _simulate_arrays(...)[..][T] but O(N_arrivals)
    instead of O(T). The state evolves linearly between arrival turns
    (garrison += production per turn while owned), so we can skip the
    per-turn loop and compute closed-form between events.

    Used by min_ships_to_own_by's owns_at, which only needs the owner at
    eval_turn â€” calling _simulate_arrays for the full array there was
    the dominant cost in plan_beam_search profiling.
    """
    H = max(0, int(math.ceil(T)))
    if H == 0:
        return planet.owner, max(0.0, float(planet.ships))
    p_prod = planet.production
    owner = planet.owner
    garrison = float(planet.ships)

    norm = []
    for t, o, s in arrivals:
        if s <= 0:
            continue
        eta = int(math.ceil(t))
        if eta < 1:
            eta = 1
        if eta > H:
            continue
        norm.append((eta, o, int(s)))
    norm.sort()

    last_t = 0
    i = 0
    n = len(norm)
    while i < n:
        eta = norm[i][0]
        if owner != -1:
            garrison += p_prod * (eta - last_t)
        j = i
        while j < n and norm[j][0] == eta:
            j += 1
        owner, garrison = resolve_arrival_event(owner, garrison, norm[i:j])
        i = j
        last_t = eta

    if owner != -1 and last_t < H:
        garrison += p_prod * (H - last_t)
    if garrison < 0:
        garrison = 0.0
    return owner, garrison


def _simulate_arrays(planet, arrivals, player, horizon):
    """Fast core: returns (owner_arr, ships_arr) as arrays indexed 0..horizon.
    Uses positional list buckets instead of dict-based by_turn (saves ~40% per call).
    Internal helper â€” use simulate_planet_timeline for the full dict API.
    """
    H = max(0, int(math.ceil(horizon)))
    p_prod = planet.production
    p_own = planet.owner
    p_sh  = float(planet.ships)
    # Bucket arrivals by turn into a list-of-lists (None for empty turns
    # saves the eta-key dict overhead, but we use a single list with idx pointer).
    # Sort arrivals once.
    norm = []
    for t, o, s in arrivals:
        if s <= 0: continue
        eta = int(math.ceil(t))
        if eta < 1: eta = 1
        if eta > H: continue
        norm.append((eta, o, int(s)))
    norm.sort()
    n_norm = len(norm)
    norm_idx = 0

    owner_arr = [p_own] * (H + 1)
    ships_arr = [max(0.0, p_sh)] * (H + 1)
    owner = p_own
    garrison = p_sh

    for turn in range(1, H + 1):
        if owner != -1:
            garrison += p_prod
        # Collect this turn's arrivals (already sorted)
        group_start = norm_idx
        while norm_idx < n_norm and norm[norm_idx][0] == turn:
            norm_idx += 1
        if norm_idx > group_start:
            prev_owner = owner
            owner, garrison = resolve_arrival_event(
                owner, garrison, norm[group_start:norm_idx]
            )
        owner_arr[turn] = owner
        if garrison < 0:
            ships_arr[turn] = 0.0
        else:
            ships_arr[turn] = garrison
    return owner_arr, ships_arr


# v40: _C_EXT_FULL is module-level (defined in header)
def simulate_planet_timeline(planet, arrivals, player: int, horizon: int) -> dict:
    """v3.3:466-539. Full forward simulation of a planet under known arrivals.

    Returns dict with owner_at, ships_at (BOTH lists indexed by turn 0..horizon
    â€” caller code that did `dict.get(turn, default)` should switch to direct
    indexing: `owner_at[turn]`), plus keep_needed, fall_turn, etc.

    v40: dispatches to C extension when available (~3x speedup).
    """
    if _C_EXT_FULL is not None:
        return _C_EXT_FULL(
            planet.owner, planet.ships, planet.production,
            arrivals, player, horizon
        )
    H = max(0, int(math.ceil(horizon)))
    owner_arr, ships_arr = _simulate_arrays(planet, arrivals, player, H)
    p_own = planet.owner

    # Detect first_enemy / fall_turn from arrays (rare events, cheap pass)
    first_enemy = None
    fall_turn = None
    min_owned = float(planet.ships) if p_own == player else 0.0
    for t in range(1, H + 1):
        ow = owner_arr[t]
        prev = owner_arr[t - 1]
        if prev == player and first_enemy is None and ow != prev:
            # any arrival flipped from player â†’ not-player implies enemy arrival
            if ow not in (-1, player):
                first_enemy = t
        if prev == player and ow != player and fall_turn is None:
            fall_turn = t
        if ow == player and ships_arr[t] < min_owned:
            min_owned = ships_arr[t]

    keep_needed = 0
    holds_full = True
    if p_own == player:
        # Cheap survives_with_keep using arrays (no closure / dict overhead)
        # We need to RE-SIMULATE with planet.ships overridden by `keep`.
        # Inline implementation; arrivals/H already known.
        norm = []
        for t, o, s in arrivals:
            if s <= 0: continue
            eta = int(math.ceil(t))
            if eta < 1: eta = 1
            if eta > H: continue
            norm.append((eta, o, int(s)))
        norm.sort()
        n_norm = len(norm)
        p_prod = planet.production

        def survives_with_keep(keep):
            sim_owner = p_own
            sim_g = float(keep)
            ni = 0
            for turn in range(1, H + 1):
                if sim_owner != -1:
                    sim_g += p_prod
                gs = ni
                while ni < n_norm and norm[ni][0] == turn:
                    ni += 1
                if ni > gs:
                    sim_owner, sim_g = resolve_arrival_event(
                        sim_owner, sim_g, norm[gs:ni]
                    )
                    if sim_owner != player:
                        return False
            return sim_owner == player

        if survives_with_keep(int(planet.ships)):
            lo, hi = 0, int(planet.ships)
            while lo < hi:
                mid = (lo + hi) // 2
                if survives_with_keep(mid):
                    hi = mid
                else:
                    lo = mid + 1
            keep_needed = lo
        else:
            holds_full = False
            keep_needed = int(planet.ships)

    return {
        "owner_at": owner_arr,
        "ships_at": ships_arr,
        "keep_needed": keep_needed,
        "min_owned": int(min_owned) if p_own == player and min_owned >= 0 else 0,
        "first_enemy": first_enemy,
        "fall_turn": fall_turn,
        "holds_full": holds_full,
        "horizon": H,
    }


def state_at_timeline(timeline: dict, arrival_turn) -> tuple:
    """Lookup (owner, ships) at given turn from a timeline. v7.15: owner_at /
    ships_at are now LISTS (indexed by turn 0..horizon), not dicts. Direct
    indexing is O(1) instead of dict-hash."""
    turn = int(math.ceil(arrival_turn))
    if turn < 0: turn = 0
    H = timeline["horizon"]
    if turn > H: turn = H
    ow = timeline["owner_at"][turn]
    sh = timeline["ships_at"][turn]
    return ow, sh if sh > 0 else 0.0


def fleet_target_planet(fleet, planets, horizon: int = HORIZON):
    """v3.3:384-409. Ray-cast a fleet against all planets to find its
    intended target. Returns (Planet, eta_turns_int) or (None, None)."""
    best_planet = None
    best_time = 1e9
    dir_x = math.cos(fleet.angle)
    dir_y = math.sin(fleet.angle)
    speed = _fleet_speed(fleet.ships)

    for planet in planets:
        dx = planet.x - fleet.x
        dy = planet.y - fleet.y
        proj = dx * dir_x + dy * dir_y
        if proj < 0:
            continue
        perp_sq = dx * dx + dy * dy - proj * proj
        radius_sq = planet.radius * planet.radius
        if perp_sq >= radius_sq:
            continue
        hit_d = max(0.0, proj - math.sqrt(max(0.0, radius_sq - perp_sq)))
        turns = hit_d / speed
        if turns <= horizon and turns < best_time:
            best_time = turns
            best_planet = planet

    if best_planet is None:
        return None, None
    return best_planet, int(math.ceil(best_time))


# â”€â”€ v56: Exact fleet-flight simulation (bit-equivalent to the Kaggle engine) â”€â”€
#
# The canonical engine (orbit_wars.py) moves every orbiting planet each tick
# (current_angle = initial_angle + angular_velocity*step) and resolves
# fleet/planet collision with a continuous swept-pair test. The old
# fleet_target_planet did a STATIC ray-cast against current planet positions â€”
# wrong for ~40% of in-flight fleets (audit 2026-05-21). v56 replaces it with
# an exact forward simulation.


def precompute_planet_tracks(planets, ang_vel, comets=None, comet_ids=None,
                              horizon: int = HORIZON):
    """Exact (x,y) of every planet for ticks 0..H.

    tick 0 = current observed position. Orbiting planets (orbital_radius +
    radius < ROTATION_RADIUS_LIMIT) rotate by ang_vel/tick â€” rotating the
    OBSERVED position by ang_vel*k is bit-identical to the engine's
    initial_angle + ang_vel*step formula. Comets follow their discrete path.

    Returns a list (in engine/observation order) of tuples
        (pid, radius, xs, ys, kmax)
    where xs/ys are length-(H+1) lists and kmax is the last collidable tick
    (= H for normal planets, shorter for comets that expire).
    """
    comet_ids = comet_ids or set()
    H = int(horizon)
    comet_path = {}
    for g in (comets or []):
        pids = g.get("planet_ids", [])
        paths = g.get("paths", [])
        pi = g.get("path_index", 0)
        for i, pid in enumerate(pids):
            if i < len(paths):
                comet_path[pid] = (paths[i], pi)

    tracks = []
    for p in planets:
        if p.id in comet_ids:
            cp = comet_path.get(p.id)
            if cp is None:
                continue  # comet with no live path â€” not collidable
            path, pi = cp
            xs, ys = [], []
            kmax = -1
            for k in range(H + 1):
                j = pi + k
                if 0 <= j < len(path):
                    xs.append(path[j][0])
                    ys.append(path[j][1])
                    kmax = k
                else:
                    xs.append(xs[-1] if xs else p.x)
                    ys.append(ys[-1] if ys else p.y)
            tracks.append((p.id, p.radius, xs, ys, kmax))
        else:
            r = math.hypot(p.x - CENTER, p.y - CENTER)
            if r + p.radius >= ROTATION_RADIUS_LIMIT:
                xs = [p.x] * (H + 1)
                ys = [p.y] * (H + 1)
            else:
                ang0 = math.atan2(p.y - CENTER, p.x - CENTER)
                xs, ys = [], []
                for k in range(H + 1):
                    a = ang0 + ang_vel * k
                    xs.append(CENTER + r * math.cos(a))
                    ys.append(CENTER + r * math.sin(a))
            tracks.append((p.id, p.radius, xs, ys, H))
    return tracks


def simulate_fleet(fx, fy, angle, ships, tracks, horizon: int = HORIZON):
    """Exact forward simulation of one fleet, bit-equivalent to the engine.

    The fleet moves `speed` units/tick in a straight line. Each tick we run
    the engine's swept-pair collision against every planet's (old,new)
    positions, in engine order (first hit wins). Out-of-bounds and sun
    crossings remove the fleet.

    Returns (pid, tick): pid is the planet hit, or None if the fleet is
    destroyed (out of bounds / sun) before reaching any planet. `tick` is
    always the tick of removal â€” arrival tick on a hit, drop tick otherwise.
    """
    speed = _fleet_speed(ships)
    cos_a = math.cos(angle)
    sin_a = math.sin(angle)
    H = int(horizon)
    for k in range(1, H + 1):
        ax, ay = fx, fy
        fx = ax + cos_a * speed
        fy = ay + sin_a * speed
        for pid, r, xs, ys, kmax in tracks:
            if k > kmax:
                continue  # comet expired
            p0x = xs[k - 1]; p0y = ys[k - 1]
            p1x = xs[k];     p1y = ys[k]
            d0x = ax - p0x;  d0y = ay - p0y
            dvx = (fx - ax) - (p1x - p0x)
            dvy = (fy - ay) - (p1y - p0y)
            a = dvx * dvx + dvy * dvy
            b = 2.0 * (d0x * dvx + d0y * dvy)
            c = d0x * d0x + d0y * d0y - r * r
            if a < 1e-12:
                if c <= 0.0:
                    return pid, k
                continue
            disc = b * b - 4.0 * a * c
            if disc < 0.0:
                continue
            sq = math.sqrt(disc)
            inv = 0.5 / a
            t1 = (-b - sq) * inv
            t2 = (-b + sq) * inv
            if t2 >= 0.0 and t1 <= 1.0:
                return pid, k
        if fx < 0.0 or fx > BOARD_SIZE or fy < 0.0 or fy > BOARD_SIZE:
            return None, k                       # dropped: out of bounds
        if _pt_seg_dist_sq(CENTER, CENTER, ax, ay, fx, fy) < _SUN_R2:
            return None, k                       # dropped: crossed the sun
    return None, H                               # unresolved within horizon


# Per-turn ledger cache. Keyed by id(fleets); the cached entry holds a
# reference to `fleets` so its id can never be reused while cached (the old
# list stays alive) â€” defeating id-reuse staleness without a turn-clear.
_LEDGER_CACHE: dict = {}


def build_arrival_ledger(fleets, planets, ang_vel=0.0, comets=None,
                          comet_ids=None, horizon: int = HORIZON) -> dict:
    """v56 â€” pid â†’ [(eta, owner, ships), ...] via EXACT fleet simulation.

    Replaces the v3.3 static ray-cast (fleet_target_planet), which mispredicted
    ~40% of in-flight fleets because it ignored planet orbital motion. Dropped
    fleets (OOB / sun) correctly produce no arrival.
    """
    key = id(fleets)
    ent = _LEDGER_CACHE.get(key)
    if (ent is not None and ent[0] is fleets and ent[1] is planets
            and ent[2] == horizon):
        return {pid: list(v) for pid, v in ent[3].items()}

    arrivals_by_planet = {p.id: [] for p in planets}
    if fleets:
        tracks = precompute_planet_tracks(planets, ang_vel, comets,
                                           comet_ids, horizon)
        for fleet in fleets:
            pid, tick = simulate_fleet(fleet.x, fleet.y, fleet.angle,
                                        fleet.ships, tracks, horizon)
            if pid is None:
                continue  # fleet destroyed before arrival â€” no ledger entry
            lst = arrivals_by_planet.get(pid)
            if lst is not None:
                lst.append((tick, fleet.owner, int(fleet.ships)))

    if len(_LEDGER_CACHE) > 8:
        _LEDGER_CACHE.clear()
    _LEDGER_CACHE[key] = (fleets, planets, horizon, arrivals_by_planet)
    return {pid: list(v) for pid, v in arrivals_by_planet.items()}


def base_timelines_for_world(world, horizon: int = HORIZON) -> dict:
    """Build all per-planet base timelines for a world. Used by plan_evaluator
    to avoid recomputing for unchanged targets.

    Returns dict pid -> timeline dict.
    """
    ledger = build_arrival_ledger(
        world.fleets, world.planets, getattr(world, 'ang_vel', 0.0),
        getattr(world, 'comets', None), getattr(world, 'comet_ids', None),
        horizon,
    )
    timelines = {}
    for p in world.planets:
        timelines[p.id] = simulate_planet_timeline(
            p, ledger[p.id], world.player, horizon
        )
    timelines["__ledger__"] = ledger
    return timelines


def _ownership_search_cap(eval_turn: int, total_production: int,
                          total_visible_ships: int) -> int:
    """v3.3:799-801. Upper bound for binary search of min_ships_to_own_by."""
    productive_cap = total_production * max(2, eval_turn + 2)
    return max(32, int(total_visible_ships + productive_cap + 32))


_TURN_CACHE: dict = {}


def clear_turn_cache() -> None:
    """Call once per agent step to flush per-turn memoization."""
    _TURN_CACHE.clear()


def min_ships_to_own_by(target_id: int, eval_turn: int, attacker_owner: int,
                         world, ledger, player: int,
                         arrival_turn=None,
                         planned_commitments=None,
                         extra_arrivals=(),
                         upper_bound=None) -> int:
    """v3.3:803-859. Minimum ships an attacker must arrive with to OWN the target
    at eval_turn (>= arrival_turn).

    Args:
        target_id: planet id
        eval_turn: turn at which ownership is evaluated
        attacker_owner: faction asking
        world: WorldModel (need: planets, planet_by_id, totals)
        ledger: dict pid -> [(eta, owner, ships), ...] (pre-built)
        player: our player slot for timeline semantics
        arrival_turn: when our extra arrives (defaults to eval_turn)
        planned_commitments: optional dict pid -> [(eta, owner, ships)] already
                             planned (e.g., from beam expansion)
        extra_arrivals: tuple of (eta, owner, ships) additional to test
        upper_bound: optional cap on binary search hi

    Returns: minimum ships needed (int), or hi+1 if infeasible within cap.
    """
    planned_commitments = planned_commitments or {}
    eval_turn = max(1, int(math.ceil(eval_turn)))
    arrival_turn = eval_turn if arrival_turn is None else max(
        1, int(math.ceil(arrival_turn))
    )
    if arrival_turn > eval_turn:
        if upper_bound is not None:
            return max(1, int(upper_bound)) + 1
        total_prod = sum(int(p.production) for p in world.planets)
        total_vis  = sum(int(p.ships) for p in world.planets) + \
                     sum(int(f.ships) for f in world.fleets)
        return _ownership_search_cap(eval_turn, total_prod, total_vis) + 1

    target = world.planet_by_id[target_id]

    normalized_extra = tuple(
        (max(1, int(math.ceil(t))), o, int(s))
        for t, o, s in extra_arrivals
        if s > 0 and max(1, int(math.ceil(t))) <= eval_turn
    )

    # Per-turn cache: keyed by (target_id, eval_turn, attacker, arrival_turn,
    # planned-hash, extra-hash). Only used when upper_bound is None (typical
    # filter call) and planned/extra are simple.
    plan_key = tuple(sorted(
        (k, tuple(sorted(v))) for k, v in planned_commitments.items()
    )) if planned_commitments else ()
    cache_key = (target_id, eval_turn, attacker_owner, arrival_turn,
                 plan_key, normalized_extra, upper_bound)
    cached = _TURN_CACHE.get(cache_key)
    if cached is not None:
        return cached

    # Build full arrivals list for projected_state at eval_turn
    base = [item for item in ledger.get(target_id, []) if item[0] <= eval_turn]
    planned = [item for item in planned_commitments.get(target_id, []) if item[0] <= eval_turn]

    # v7.15 fast path: pre-build the SORTED full arrivals (base + planned +
    # normalized_extra) ONCE; for owns_at(X) we only add (arrival_turn,
    # attacker, X) and re-simulate via _simulate_arrays (list-based, faster
    # than the dict wrapper).
    sim_arrivals = base + planned + list(normalized_extra)

    # Without extra: who owns at eval_turn?
    # v7.21: use _owner_ships_at_T (closed-form) â€” we only need state AT
    # eval_turn, not the full per-turn array.
    owner_before, ships_before_at_eval = _owner_ships_at_T(
        target, sim_arrivals, eval_turn
    )
    if owner_before == attacker_owner:
        _TURN_CACHE[cache_key] = 0
        return 0

    def owns_at(ships: int) -> bool:
        # v7.21: only the owner AT eval_turn matters here, so use the
        # closed-form _owner_ships_at_T (O(N_arrivals)) instead of the
        # full _simulate_arrays (O(eval_turn)).
        arrivals_test = sim_arrivals + [(arrival_turn, attacker_owner, int(ships))]
        ow, _ = _owner_ships_at_T(target, arrivals_test, eval_turn)
        return ow == attacker_owner

    # Use ships at eval_turn from base sim (no extra) as a starting hi
    ships_before = ships_before_at_eval if ships_before_at_eval > 0 else 0.0

    if upper_bound is not None:
        hi = max(1, int(upper_bound))
        if not owns_at(hi):
            return hi + 1
    else:
        hi = max(1, int(math.ceil(ships_before)) + 1)
        total_prod = sum(int(p.production) for p in world.planets)
        total_vis  = sum(int(p.ships) for p in world.planets) + \
                     sum(int(f.ships) for f in world.fleets)
        search_cap = _ownership_search_cap(eval_turn, total_prod, total_vis)
        while hi <= search_cap and not owns_at(hi):
            hi *= 2
        if hi > search_cap:
            hi = search_cap
            if not owns_at(hi):
                return hi + 1

    lo = 1
    while lo < hi:
        mid = (lo + hi) // 2
        if owns_at(mid):
            hi = mid
        else:
            lo = mid + 1
    _TURN_CACHE[cache_key] = lo
    return lo


def ships_needed_to_capture(target_id: int, arrival_turn: int, world, ledger,
                             player: int, planned_commitments=None,
                             extra_arrivals=()) -> int:
    """v3.3:903-904 convenience wrapper. Min ships for `player` to capture target."""
    return min_ships_to_own_by(
        target_id, arrival_turn, player, world, ledger, player,
        arrival_turn=arrival_turn,
        planned_commitments=planned_commitments,
        extra_arrivals=extra_arrivals,
    )


