# â”€â”€ Constants (mirror v3.3 main.py) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
CENTER_X = CENTER_Y      = 50.0
SUN_R                    = 10.0
SUN_SAFETY               = 1.5
LAUNCH_CLEARANCE         = 0.1
ROTATION_LIMIT           = 50.0
MAX_SPEED                = 6.0
INTERCEPT_TOLERANCE      = 1     # v3.3 uses 1; aim/intercept fns tighter than ledger build
ROUTE_SEARCH_HORIZON     = 60
SIM_HORIZON              = 110

PLAN_DEPTH               = 4     # v7.21 bumped 3 â†’ 4 (deadline-bounded inside beam)
PLAN_BEAM_WIDTH          = 6
PLAN_MAX_EXTRA_WAIT      = 12


# â”€â”€ Geometric helpers (v3.3 port) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

def _dist(ax, ay, bx, by):
    return math.hypot(ax - bx, ay - by)


def _is_static_planet(planet):
    r = _dist(planet.x, planet.y, CENTER_X, CENTER_Y)
    return r + planet.radius >= ROTATION_LIMIT


def _launch_point(sx, sy, sr, angle):
    clearance = sr + LAUNCH_CLEARANCE
    return sx + math.cos(angle) * clearance, sy + math.sin(angle) * clearance


def _point_to_segment_distance(px, py, x1, y1, x2, y2):
    dx = x2 - x1
    dy = y2 - y1
    seg_len_sq = dx * dx + dy * dy
    if seg_len_sq <= 1e-9:
        return _dist(px, py, x1, y1)
    t = ((px - x1) * dx + (py - y1) * dy) / seg_len_sq
    t = max(0.0, min(1.0, t))
    proj_x = x1 + t * dx
    proj_y = y1 + t * dy
    return _dist(px, py, proj_x, proj_y)


def _segment_hits_sun(x1, y1, x2, y2, safety=SUN_SAFETY):
    return _point_to_segment_distance(CENTER_X, CENTER_Y, x1, y1, x2, y2) < SUN_R + safety


def _actual_path_geometry(sx, sy, sr, tx, ty, tr):
    angle = math.atan2(ty - sy, tx - sx)
    start_x, start_y = _launch_point(sx, sy, sr, angle)
    hit_distance = max(0.0, _dist(sx, sy, tx, ty) - (sr + LAUNCH_CLEARANCE) - tr)
    end_x = start_x + math.cos(angle) * hit_distance
    end_y = start_y + math.sin(angle) * hit_distance
    return angle, start_x, start_y, end_x, end_y, hit_distance


def _safe_angle_and_distance(sx, sy, sr, tx, ty, tr):
    angle, start_x, start_y, end_x, end_y, hit_distance = _actual_path_geometry(
        sx, sy, sr, tx, ty, tr
    )
    if _segment_hits_sun(start_x, start_y, end_x, end_y):
        return None
    return angle, hit_distance


def _estimate_arrival(sx, sy, sr, tx, ty, tr, ships):
    safe = _safe_angle_and_distance(sx, sy, sr, tx, ty, tr)
    if safe is None:
        return None
    angle, total_d = safe
    turns = max(1, int(math.ceil(total_d / _fleet_speed(max(1, ships)))))
    return angle, turns


def _predict_planet_position(planet, initial_by_id, ang_vel, turns,
                              comets=None, comet_ids=None):
    # Comets follow a pre-computed path, not a circular orbit.
    if comet_ids and planet.id in comet_ids and comets:
        for group in comets:
            pids = group.get("planet_ids", [])
            if planet.id not in pids:
                continue
            idx = pids.index(planet.id)
            paths = group.get("paths", [])
            pi = group.get("path_index", 0)
            if idx >= len(paths):
                return planet.x, planet.y
            path = paths[idx]
            future_idx = pi + int(turns)
            if 0 <= future_idx < len(path):
                return path[future_idx][0], path[future_idx][1]
            return planet.x, planet.y  # comet expired beyond path end
    # Use current position for orbital radius â€” avoids bogus initial positions
    # (e.g. comet sentinel x=-99,y=-99 in initial_by_id if comet_ids not passed).
    r = _dist(planet.x, planet.y, CENTER_X, CENTER_Y)
    if r + planet.radius >= ROTATION_LIMIT:
        return planet.x, planet.y
    cur_ang = math.atan2(planet.y - CENTER_Y, planet.x - CENTER_X)
    new_ang = cur_ang + ang_vel * turns
    return (CENTER_X + r * math.cos(new_ang), CENTER_Y + r * math.sin(new_ang))


def _target_can_move(target, initial_by_id, comet_ids=None):
    if comet_ids and target.id in comet_ids:
        return True  # comets move along their path
    r = _dist(target.x, target.y, CENTER_X, CENTER_Y)
    return r + target.radius < ROTATION_LIMIT


def _comet_remaining_life(target_id, comets, comet_ids):
    """Returns remaining steps a comet target exists for, or float('inf') if
    the target is not a comet. Used to filter target captures whose ETA exceeds
    the comet's remaining lifetime â€” firing at a comet that will expire mid-
    flight is wasted ships (the fleet flies into empty space).
    """
    if target_id not in comet_ids:
        return float('inf')
    for group in comets:
        pids = group.get("planet_ids", [])
        if target_id not in pids:
            continue
        idx = pids.index(target_id)
        paths = group.get("paths", [])
        pi = group.get("path_index", 0)
        if idx >= len(paths):
            return 0
        path = paths[idx]
        return max(0, len(path) - pi)
    return 0


def _search_safe_intercept(src, target, ships, initial_by_id, ang_vel,
                            comets=None, comet_ids=None):
    """v3.3:313-349 â€” search for orbit/comet intercept when direct path blocked."""
    best = None
    best_score = None
    max_turns = min(SIM_HORIZON, ROUTE_SEARCH_HORIZON)

    for candidate_turns in range(1, max_turns + 1):
        pos = _predict_planet_position(target, initial_by_id, ang_vel,
                                        candidate_turns, comets, comet_ids)
        if pos is None:
            continue
        est = _estimate_arrival(src.x, src.y, src.radius, pos[0], pos[1],
                                 target.radius, ships)
        if est is None:
            continue
        _, turns = est
        if abs(turns - candidate_turns) > INTERCEPT_TOLERANCE:
            continue

        actual_turns = max(turns, candidate_turns)
        actual_pos = _predict_planet_position(target, initial_by_id, ang_vel,
                                               actual_turns, comets, comet_ids)
        if actual_pos is None:
            continue

        confirm = _estimate_arrival(src.x, src.y, src.radius, actual_pos[0],
                                      actual_pos[1], target.radius, ships)
        if confirm is None:
            continue

        delta = abs(confirm[1] - actual_turns)
        if delta > INTERCEPT_TOLERANCE:
            continue

        score = (delta, confirm[1], candidate_turns)
        if best is None or score < best_score:
            best_score = score
            best = (confirm[0], confirm[1], actual_pos[0], actual_pos[1])

    return best


def _aim_with_prediction(src, target, ships, initial_by_id, ang_vel,
                          comets=None, comet_ids=None):
    """v3.3:351-382 + comet path prediction."""
    # Comets follow discrete path steps, not smooth orbits. The iterative
    # position-refinement loop oscillates when the comet passes near the source
    # (predicted target at t=N is essentially overhead â†’ ETAâ†’0 â†’ re-predict
    # at t~0 â†’ far away â†’ ETA=N â†’ loop). Use the exhaustive-scan path directly.
    if comet_ids and target.id in comet_ids:
        return _search_safe_intercept(src, target, ships, initial_by_id, ang_vel,
                                       comets, comet_ids)

    est = _estimate_arrival(src.x, src.y, src.radius, target.x, target.y,
                              target.radius, ships)
    if est is None:
        if not _target_can_move(target, initial_by_id, comet_ids):
            return None
        return _search_safe_intercept(src, target, ships, initial_by_id, ang_vel,
                                       comets, comet_ids)

    tx, ty = target.x, target.y
    for _ in range(5):
        _, turns = est
        pos = _predict_planet_position(target, initial_by_id, ang_vel, turns,
                                        comets, comet_ids)
        if pos is None:
            return None
        ntx, nty = pos
        next_est = _estimate_arrival(src.x, src.y, src.radius, ntx, nty,
                                       target.radius, ships)
        if next_est is None:
            if not _target_can_move(target, initial_by_id, comet_ids):
                return None
            return _search_safe_intercept(src, target, ships, initial_by_id,
                                           ang_vel, comets, comet_ids)
        if (
            abs(ntx - tx) < 0.3
            and abs(nty - ty) < 0.3
            and abs(next_est[1] - turns) <= INTERCEPT_TOLERANCE
        ):
            return next_est[0], next_est[1], ntx, nty
        tx, ty = ntx, nty
        est = next_est

    final_est = _estimate_arrival(src.x, src.y, src.radius, tx, ty,
                                    target.radius, ships)
    if final_est is None:
        return _search_safe_intercept(src, target, ships, initial_by_id, ang_vel,
                                       comets, comet_ids)
    return final_est[0], final_est[1], tx, ty


# â”€â”€ Plan primitives â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

def plan_best_launch(src_id, src_planet, ref_ships, ref_prod, ref_time,
                      target, world, R, ledger=None, player=None,
                      planned_commitments=None):
    """v3.3:2188-2239 + v7.14 exact min_ships_to_own_by.

    Source has ref_ships at ref_time, produces ref_prod/turn. Search candidate
    launch times t âˆˆ [ref_time, ref_time+PLAN_MAX_EXTRA_WAIT] for earliest
    feasible launch. Returns dict(t_launch, fleet, eta, cap_t) or None.
    """
    if ref_prod <= 0 and ref_ships < 1:
        return None
    if player is None:
        player = world.player
    if ledger is None:
        ledger = build_arrival_ledger(
            world.fleets, world.planets, world.ang_vel,
            world.comets, world.comet_ids)

    best = None
    src_static = _is_static_planet(src_planet)
    tgt_static = _is_static_planet(target)
    _comets = getattr(world, 'comets', None)
    _comet_ids = getattr(world, 'comet_ids', None)

    for extra in range(0, PLAN_MAX_EXTRA_WAIT + 1):
        t = ref_time + extra
        if t >= R:
            break
        fleet_avail = ref_ships + ref_prod * (t - ref_time)
        if fleet_avail < 1:
            continue
        speed = _fleet_speed(fleet_avail)
        if src_static or t == 0:
            sx, sy = src_planet.x, src_planet.y
        else:
            sx, sy = _predict_planet_position(src_planet, world.initial_by_id,
                                               world.ang_vel, t,
                                               _comets, _comet_ids)
        # v40 ETA FIX (from v9.9b): edge-to-edge distance. Fleet ends when it
        # touches the target's surface from outside the source surface.
        # Center-to-center over-estimated our ETA by ~2 turns, causing anti-snipes.
        _margin = src_planet.radius + LAUNCH_CLEARANCE + target.radius
        if tgt_static and not (_comet_ids and target.id in _comet_ids):
            eta = max(0.0, _dist(sx, sy, target.x, target.y) - _margin) / speed
        else:
            eta = max(0.0, _dist(sx, sy, target.x, target.y) - _margin) / speed
            for _ in range(4):
                px, py = _predict_planet_position(target, world.initial_by_id,
                                                    world.ang_vel, t + eta,
                                                    _comets, _comet_ids)
                new_eta = max(0.0, _dist(sx, sy, px, py) - _margin) / speed
                if abs(new_eta - eta) < 0.05:
                    eta = new_eta
                    break
                eta = new_eta
        cap_t = t + eta
        if cap_t >= R:
            continue
        cap_t_int = int(math.ceil(cap_t))

        # v7.32 comet-life filter: if target is a comet and our fleet arrives
        # AFTER the comet expires, the fleet flies into empty space â€” pure
        # waste. Skip the launch. comet_remaining_life returns inf for non-comet
        # targets (no effect on normal planet captures).
        comet_life = _comet_remaining_life(target.id, world.comets, world.comet_ids)
        if cap_t_int >= comet_life:
            continue

        # EXACT minimum: simulate target timeline with planned commitments.
        needed = min_ships_to_own_by(
            target.id, cap_t_int, player, world, ledger, player,
            arrival_turn=cap_t_int,
            planned_commitments=planned_commitments,
            upper_bound=max(32, int(fleet_avail) * 2),
        )

        if fleet_avail < needed:
            continue  # cannot capture even with this fleet â€” wait more

        # Feasible. Fire ALL ships available at the source: residual at the
        # captured target = fleet_avail - garrison_at_cap is larger, giving
        # better self-defense buffer.
        if best is None or cap_t < best["cap_t"]:
            best = {
                "t_launch":   t,
                "fleet":      int(fleet_avail),       # fire everything
                "fleet_min":  int(needed),            # bookkeeping for residual
                "eta":        eta,
                "cap_t":      cap_t,
                "fleet_at_src": int(fleet_avail),
            }
        if extra > 5 and best is not None and cap_t > best["cap_t"] + 1.0:
            break
    return best


def max_enemy_threat_within_horizon(my_planet, world, horizon: int = 25):
    """v7.14 â€” estimate the MAX ship-count of any single enemy fleet that
    could ARRIVE at my_planet within `horizon` turns. Used for defensive ship
    reservation at sources.

    For each enemy planet, find smallest W in [0, horizon] such that the
    fleet (S + prod*W) launched at time W arrives at my_planet within horizon.
    Track max such fleet across all enemies Ã— W values.
    """
    best = 0
    for src in world.planets:
        if src.owner == world.player or src.owner == -1:
            continue
        for W in range(0, horizon):
            fleet = int(src.ships) + int(src.production) * W
            if fleet <= 0:
                continue
            speed = _fleet_speed(fleet)
            # v40 ETA FIX: edge-to-edge (see plan_best_launch).
            _margin = src.radius + LAUNCH_CLEARANCE + my_planet.radius
            if _is_static_planet(my_planet):
                eta = max(0.0, _dist(src.x, src.y, my_planet.x, my_planet.y) - _margin) / speed
            else:
                eta = max(0.0, _dist(src.x, src.y, my_planet.x, my_planet.y) - _margin) / speed
                for _ in range(2):
                    px, py = _predict_planet_position(my_planet,
                                                       world.initial_by_id,
                                                       world.ang_vel, W + eta)
                    eta = max(0.0, _dist(src.x, src.y, px, py) - _margin) / speed
            arrival = W + eta
            if arrival <= horizon:
                if fleet > best:
                    best = fleet
                break  # bigger W = bigger fleet â†’ done if already best
    return best


def enemy_earliest_capture(target, world, garrison_override=None):
    """v3.3:2241-2272. Time-to-capture for the fastest enemy planet against
    a target with effective garrison `garrison_override` (default target.ships).
    """
    best = float("inf")
    G = int(target.ships) if garrison_override is None else int(garrison_override)
    for src in world.planets:
        if src.owner == world.player or src.owner == -1:
            continue
        S = int(src.ships)
        p_rate = int(src.production)
        for W in range(0, 40):
            fleet = S + p_rate * W
            if fleet < G + 1:
                continue
            speed = _fleet_speed(fleet)
            # v40 ETA FIX: edge-to-edge (see plan_best_launch).
            _margin = src.radius + LAUNCH_CLEARANCE + target.radius
            if _is_static_planet(target):
                eta = max(0.0, _dist(src.x, src.y, target.x, target.y) - _margin) / speed
            else:
                eta = max(0.0, _dist(src.x, src.y, target.x, target.y) - _margin) / speed
                for _ in range(2):
                    px, py = _predict_planet_position(target, world.initial_by_id,
                                                        world.ang_vel, W + eta)
                    eta = max(0.0, _dist(src.x, src.y, px, py) - _margin) / speed
            t = W + eta
            if t < best:
                best = t
            if W > 5 and t > best:
                break
    return best


def enemy_recapture_time(target, world, our_cap_t, our_fleet_size):
    """v7.14 â€” Estimate the earliest time an enemy can RECAPTURE target after
    our capture at our_cap_t with our_fleet_size ships.

    At our_cap_t the planet has `residual = our_fleet_size âˆ’ target.ships`
    ships. From there it produces target.production/turn. The enemy needs to
    bring `garrison_at_arrival + 1` ships, where garrison grows from residual.

    Returns absolute turn (relative to current step) of earliest enemy
    recapture, or float("inf") if no enemy can recapture within horizon.
    """
    residual = max(0, our_fleet_size - int(target.ships))
    best = float("inf")
    for src in world.planets:
        if src.owner == world.player or src.owner == -1:
            continue
        S = int(src.ships)
        p_rate = int(src.production)
        # Enemy can start sending immediately. Try W = 0..40 wait before launch.
        for W in range(0, 40):
            fleet = S + p_rate * W
            if fleet < 1:
                continue
            speed = _fleet_speed(fleet)
            # v40 ETA FIX: edge-to-edge (see plan_best_launch).
            _margin = src.radius + LAUNCH_CLEARANCE + target.radius
            if _is_static_planet(target):
                eta = max(0.0, _dist(src.x, src.y, target.x, target.y) - _margin) / speed
            else:
                eta = max(0.0, _dist(src.x, src.y, target.x, target.y) - _margin) / speed
                for _ in range(2):
                    px, py = _predict_planet_position(target, world.initial_by_id,
                                                        world.ang_vel, W + eta)
                    eta = max(0.0, _dist(src.x, src.y, px, py) - _margin) / speed
            arrival_t = W + eta
            if arrival_t <= our_cap_t:
                continue  # enemy beats us â€” race-filter already catches
            # Garrison at arrival_t: residual + production * (arrival_t - our_cap_t)
            garrison_at_arr = residual + int(target.production) * (arrival_t - our_cap_t)
            if fleet >= garrison_at_arr + 1:
                if arrival_t < best:
                    best = arrival_t
            if W > 5 and arrival_t > best:
                break
    return best


def plan_evaluate(plan, world, ledger, enemy_earliest=None):
    """v3.3:2274-2351. Evaluate a plan of (src_id, tgt_id) commitments.

    Returns dict(V, moves, plan_pairs) or None if plan is infeasible.

    V is V_state(H=min(R,200)): zero-sum forward-sim differential.
    The plan_pairs key carries the (src,tgt) list for chain extension.
    """
    R = world.remaining_steps
    player = world.player
    sources = {}
    # v7.14 defense reservation: each source reserves
    #   reserved = max(keep_needed, threat_within_horizon)
    # - keep_needed: from base_timeline (in-flight enemy fleets, exact)
    # - threat_within_horizon: max single enemy fleet that COULD arrive
    #   (projected attack from any enemy planet in next H turns)
    # The remainder is offense_avail = ships - reserved.
    base_timelines = world.__dict__.get('_v7_14_base_timelines')
    threat_map = world.__dict__.get('_v7_14_threat_map')

    # v9.4: IBR-AWARE DEFENSE RESERVATION.
    # The IBR projection (already computed for V_state forward-sim) is enemy's
    # BEST plan against passive us. It enumerates concrete fleet sizes + arrival
    # times targeting our planets. Use it to reserve defense.
    #
    # Principled (not heuristic):
    # - keep_needed defends against IN-FLIGHT enemy fleets only (exact, narrow).
    # - max_enemy_threat_within_horizon over-reserves (pessimistic worst-case).
    # - IBR projection = enemy's predicted-likely play â†’ reserve against THAT.
    #
    # Pattern this fixes (match 096 v7.34 vs v7.32, step 60-80 collapse):
    # mid-game IBR predicts enemy launches at our planets. Without this term,
    # we over-commit to expansion; captured planets undefended; predicted
    # enemy attacks land at empty garrisons; we collapse.
    my_pids = {p.id for p in world.my_planets}
    ibr_proj = world.__dict__.get('_v7_30_enemy_projections') or []
    # v40 CAP: only count IBR projections arriving within IBR_DEFENSE_HORIZON.
    # Beyond ~25 turns enemy will re-plan in response to our moves.
    IBR_DEFENSE_HORIZON = 25
    ibr_threat: dict = {}
    for proj in ibr_proj:
        tgt = proj.get('tgt_id')
        cap_t = proj.get('cap_t', 999)
        if tgt in my_pids and cap_t <= IBR_DEFENSE_HORIZON:
            ibr_threat[tgt] = ibr_threat.get(tgt, 0) + int(proj.get('fleet', 0))

    for planet in world.my_planets:
        if base_timelines is not None and planet.id in base_timelines:
            keep = base_timelines[planet.id]["keep_needed"]
        else:
            tl = simulate_planet_timeline(planet, ledger.get(planet.id, []),
                                            player, 100)
            keep = tl["keep_needed"]
        # v40 CAP (from v9.5): reservation = max(keep_needed, CAPPED IBR threats).
        # Cap IBR reservation at ships//2: always preserve >=50% for offense.
        # Fixes over-reservation vs sub-optimal opponents (they don't follow IBR).
        ibr_t = ibr_threat.get(planet.id, 0)
        ibr_t_capped = min(int(ibr_t), int(planet.ships) // 2)
        reserved = max(int(keep), int(ibr_t_capped))
        offense_avail = max(0, int(planet.ships) - reserved)
        sources[planet.id] = (offense_avail, int(planet.production), 0)

    # Pre-populate targets being captured by friendly in-flight fleets
    in_flight_captures: set = set()
    for pid, arrivals in ledger.items():
        if isinstance(pid, str):  # skip "__ledger__" sentinel if present
            continue
        planet = world.planet_by_id.get(pid)
        if planet is None or planet.owner == player:
            continue
        friendly = sorted(
            [(eta, ships) for eta, owner, ships in arrivals if owner == player],
            key=lambda x: x[0],
        )
        if not friendly:
            continue
        garrison = int(planet.ships)
        cumulative = 0
        for eta, ships in friendly:
            cumulative += ships
            if cumulative > garrison:
                residual = cumulative - garrison
                sources[pid] = (residual, int(planet.production), eta)
                in_flight_captures.add(pid)
                break

    V = 0.0
    moves = []
    # v7.15 swarm: a target can appear multiple times. First commit credits
    # V normally; subsequent commits are SWARM/REINFORCE (small bonus only,
    # no double-count). Sources still drained for each commit.
    captured_targets: dict = {}   # tgt_id -> first cap_t (for V credit)

    for src_id, tgt_id in plan:
        if src_id not in sources:
            return None
        if tgt_id == src_id:
            return None
        ref_ships, ref_prod, ref_t = sources[src_id]
        if ref_ships < 1 and ref_prod < 1:
            return None
        src_planet = world.planet_by_id[src_id]
        target = world.planet_by_id[tgt_id]
        already_in_plan = {t for _, t in plan[:len(moves)]}
        if target.owner == player and tgt_id not in already_in_plan:
            return None  # own planet â€” no reinforcement
        if tgt_id in in_flight_captures and tgt_id not in already_in_plan:
            return None  # in-flight already capturing

        # Build planned_commitments dict for min_ships query (chain+swarm aware)
        planned = {}
        for prev_commit in moves:
            tgt = prev_commit["tgt_id"]
            arr = int(math.ceil(prev_commit["cap_t"]))
            planned.setdefault(tgt, []).append((arr, player, prev_commit["fleet"]))

        launch = plan_best_launch(src_id, src_planet, ref_ships, ref_prod,
                                    ref_t, target, world, R,
                                    ledger=ledger, player=player,
                                    planned_commitments=planned)
        if launch is None:
            return None

        # v9.9 SNIPE-AWARE RACE FILTER:
        # Old: drop plan if enemy reaches target before us (enemy_earliest < cap_t - 0.5).
        # New: drop only if enemy gets there MUCH earlier (> 8 turns), because
        # for enemies that arrive 1-8 turns before, they captured target with
        # low residual ships (just-captured planets have small garrison =
        # capture_fleet - target.ships, then enemy_prod * (delay) added).
        # We can SNIPE if our fleet_avail >> enemy's expected garrison at cap_t.
        # Estimate enemy garrison at cap_t conservatively:
        #   enemy_residual = max(0, enemy_capture_fleet - target.ships)
        #   enemy_garrison_at_cap_t = enemy_residual + target.production * (cap_t - enemy_earliest)
        # If fleet_avail > enemy_garrison + target.ships, snipe is feasible.
        if (enemy_earliest is not None and tgt_id in enemy_earliest
                and target.owner == -1 and tgt_id not in captured_targets):
            enemy_t = enemy_earliest[tgt_id]
            cap_t = launch["cap_t"]
            # Wide drop: enemy way too early, snipe infeasible
            if enemy_t < cap_t - 8.0:
                return None
            # Snipe window: enemy arrives 0-8 turns before us
            if enemy_t < cap_t - 0.5:
                # Estimate enemy garrison growth between enemy_t and cap_t
                gap = max(0.0, cap_t - enemy_t)
                # Conservative enemy capture fleet â‰ˆ 1.5 Ã— target.ships
                # (enough to capture neutral with small buffer)
                est_enemy_capture = int(target.ships) * 2
                est_enemy_residual = max(0, est_enemy_capture - int(target.ships))
                est_enemy_garrison = (est_enemy_residual
                                        + int(target.production) * int(gap))
                # We need ships > est_enemy_garrison + 1 to capture
                snipe_min = est_enemy_garrison + 2
                if int(launch["fleet"]) < snipe_min:
                    return None
                # Otherwise: snipe is feasible â€” keep the plan

        is_first_capture = (tgt_id not in captured_targets)
        if is_first_capture:
            captured_targets[tgt_id] = launch["cap_t"]
        # V accumulation here is overwritten by V_state below â€” skip it.

        moves.append({
            "src_id": src_id,
            "tgt_id": tgt_id,
            "t_launch": launch["t_launch"],
            "fleet": launch["fleet"],
            "eta": launch["eta"],
            "cap_t": launch["cap_t"],
            "production": int(target.production),
            "fleet_at_src": launch.get("fleet_at_src", launch["fleet"]),
            "is_swarm": not is_first_capture,
        })
        # Source drained
        leftover_at_src = max(0, launch.get("fleet_at_src", launch["fleet"]) -
                               launch["fleet"])
        sources[src_id] = (leftover_at_src, ref_prod, launch["t_launch"])
        # Target-as-source: first capture sets residual; swarm adds to it.
        if is_first_capture:
            residual = max(0, launch["fleet"] - int(target.ships))
            sources[tgt_id] = (residual, int(target.production), launch["cap_t"])
        else:
            cur_ships, cur_prod, _ = sources.get(
                tgt_id, (0, int(target.production), launch["cap_t"])
            )
            sources[tgt_id] = (cur_ships + launch["fleet"], cur_prod,
                               launch["cap_t"])

    # v51: store plan_pairs for chain extension in plan_simultaneous_search
    plan_pairs_result = list(plan)

    # v7.30 FORWARD-SIM V: replace static "sum of capture gains" with the
    # actual game-state evaluation at horizon H. Builds virtual_ledger by
    # adding our plan's fleets as virtual arrivals. simulate_planet_timeline
    # already handles per-step production, arrival resolution, captures, and
    # recaptures. We then compute V_state(H) = production differential at H,
    # projected over remaining match time.
    #
    # This is the same paradigm as lb-highest-1000's forward-sim + value-fn;
    # we use a hand-derived V instead of learned V, but the structure mirrors
    # it. Principled: derived from "future production advantage", no magic.
    # v7.32: bumped H from 30 to 60. Longer horizon = see further future state
    # = better V for plans whose payoff unfolds over many turns. With production
    # accumulating, ship asset, and recapture dynamics, 30 was undercounting
    # the long-term value of certain captures (especially high-prod planets
    # that take time to pay off).
    # v41.0: bumped H from 60 to min(R, 200). Core game dynamics (recaptures,
    # enemy response) unfold over 150+ steps. H=60 blind to mid/late-game threats.
    # With C-ext, simulate_planet_timeline(H=200) costs ~3Ã— more per call but
    # plan_beam_search is still within budget (deadline-bounded). Extrapolation
    # only applies beyond H â†’ much more accurate.
    SIM_H = min(world.remaining_steps, 200)
    H = min(SIM_H, R)
    if H > 0 and len(moves) > 0:
        # Build virtual arrivals dict: real ledger + our plan's fleets +
        # IBR-projected enemy fleets (so forward-sim accounts for enemy reactions,
        # not passive enemy). Without enemy projection, V is optimistic â€” we plan
        # captures assuming enemy stays put. With enemy projection, V reflects
        # the actual zero-sum dynamic.
        virtual_arrivals: dict = {}
        for pid, arr_list in ledger.items():
            if isinstance(pid, str):
                continue
            virtual_arrivals[pid] = list(arr_list)
        # Our plan's fleets
        for mv in moves:
            tgt = mv["tgt_id"]
            cap_t = mv["cap_t"]
            fleet = mv["fleet"]
            eta_int = int(math.ceil(cap_t))
            if eta_int <= H:
                virtual_arrivals.setdefault(tgt, []).append(
                    (eta_int, player, fleet)
                )
        # IBR enemy projections (filled by main.py predict_enemy_plan)
        ibr_proj = world.__dict__.get('_v7_30_enemy_projections') or []
        for proj in ibr_proj:
            tgt = proj["tgt_id"]
            cap_t = proj["cap_t"]
            fleet = proj["fleet"]
            slot = proj["enemy_slot"]
            if cap_t <= H:
                virtual_arrivals.setdefault(tgt, []).append(
                    (cap_t, slot, fleet)
                )
        # v7.31 COMPLETE V_STATE(H): includes both future-production-flow AND
        # ship-asset-value at horizon. All in same unit ("ship equivalent" since
        # ships fight 1:1 in battles and 1 ship â‰ˆ 1 turn of prod=1).
        #
        #   V_state(H) = Î£_planet sign(owner_H) Ã— prod Ã— (R - H)   [future flow]
        #              + Î£_planet sign(owner_H) Ã— ships_at_H        [garrison asset]
        #              + Î£_fleet_in_flight_H sign(owner) Ã— ships     [in-transit asset]
        #
        # Zero-sum: V is the differential my_total_strength - enemy_total_strength.
        # No magic coefficient â€” each term is in raw ship units, derived from
        # the game mechanics (production = ships per turn, fight is 1:1).
        V_state = 0.0
        for planet in world.planets:
            arrivals_p = virtual_arrivals.get(planet.id, [])
            tl = simulate_planet_timeline(planet, arrivals_p, player, H)
            owner_at = tl["owner_at"]
            ships_at = tl["ships_at"]
            idx = H if H < len(owner_at) else len(owner_at) - 1
            owner_H = owner_at[idx]
            ships_H = ships_at[idx] if idx < len(ships_at) else 0
            future_prod = int(planet.production) * (R - H)
            if owner_H == player:
                V_state += future_prod + ships_H
            elif owner_H != -1:
                V_state -= future_prod + ships_H
            # Neutral: contributes 0 (no owner, ships don't matter for V differential)
        # In-flight fleets still en route at step H. From virtual_arrivals
        # (real + plan + IBR enemy), count each arrival whose eta > H.
        for pid, arrs in virtual_arrivals.items():
            for eta, owner, ships in arrs:
                if eta > H:
                    if owner == player:
                        V_state += ships
                    elif owner != -1:
                        V_state -= ships
        # V_state replaces capture-based V. Keep moves bookkeeping intact.
        V = V_state

    return {"V": V, "moves": moves, "plan_pairs": plan_pairs_result}


def plan_beam_search(world, ledger=None, depth=PLAN_DEPTH,
                      beam_width=PLAN_BEAM_WIDTH, deadline=None):
    """v3.3:2353-2415. Beam over plans; returns best plan dict or None."""
    if ledger is None:
        ledger = build_arrival_ledger(
            world.fleets, world.planets, world.ang_vel,
            world.comets, world.comet_ids, SIM_HORIZON)

    player = world.player
    all_targets = [p for p in world.planets if p.owner != player]
    if not all_targets:
        return None

    enemy_earliest = {
        t.id: enemy_earliest_capture(t, world) for t in all_targets
    }

    initial_sources = {p.id for p in world.my_planets}
    plans = [{"plan": [], "V": 0.0, "moves": []}]
    # Track best plan ACROSS all depths (not just last layer). A short plan
    # may have higher V than longer extensions if no extension is feasible.
    best_overall = None

    # v7.15: allow up to MAX_SWARM_PER_TARGET commits on the same target
    # (enables multi-source swarm captures). Beyond that, target is "saturated".
    # v7.15-rc2: allow source REUSE up to MAX_SRC_USES (production rebuilds it).
    MAX_SWARM_PER_TARGET = 2
    MAX_SRC_USES = 2

    for _ in range(depth):
        if deadline is not None and time.perf_counter() >= deadline:
            break
        new_plans = []
        for entry in plans:
            if deadline is not None and time.perf_counter() >= deadline:
                break
            prev_plan = entry["plan"]
            tgt_count: dict = {}
            for _, t in prev_plan:
                tgt_count[t] = tgt_count.get(t, 0) + 1
            # Source-use count (allow reuse if production refills source)
            src_count: dict = {}
            for s, _ in prev_plan:
                src_count[s] = src_count.get(s, 0) + 1
            # Available sources: initial + captured-in-plan, capped per source
            avail_sources = set(initial_sources) | set(tgt_count.keys())
            avail_sources = {s for s in avail_sources
                              if src_count.get(s, 0) < MAX_SRC_USES}
            for src_id in avail_sources:
                if deadline is not None and time.perf_counter() >= deadline:
                    break
                for tgt in all_targets:
                    if deadline is not None and time.perf_counter() >= deadline:
                        break
                    if tgt.id == src_id:
                        continue
                    # Saturated target: skip
                    if tgt_count.get(tgt.id, 0) >= MAX_SWARM_PER_TARGET:
                        continue
                    new_plan = prev_plan + [(src_id, tgt.id)]
                    res = plan_evaluate(new_plan, world, ledger,
                                         enemy_earliest=enemy_earliest)
                    if res is None:
                        continue
                    cand = {
                        "plan": new_plan,
                        "V": res["V"],
                        "moves": res["moves"],
                    }
                    new_plans.append(cand)
                    if best_overall is None or cand["V"] > best_overall["V"]:
                        best_overall = cand
        if not new_plans:
            break
        seen = {}
        for p in new_plans:
            key = tuple(p["plan"])
            if key not in seen or p["V"] > seen[key]["V"]:
                seen[key] = p
        candidates = sorted(seen.values(), key=lambda x: -x["V"])
        plans = candidates[:beam_width]

    return best_overall


def plan_shot(src_id, tgt_id, ships, world):
    """Convenience wrapper around _aim_with_prediction matching v3.3 plan_shot
    return shape: (angle, eta, tx, ty) or None.
    """
    src = world.planet_by_id[src_id]
    target = world.planet_by_id[tgt_id]
    return _aim_with_prediction(src, target, int(ships),
                                  world.initial_by_id, world.ang_vel,
                                  getattr(world, 'comets', None),
                                  getattr(world, 'comet_ids', None))


class _MirrorWorld:
    """v7.15 IBR helper: lightweight wrapper exposing world from another
    player's POV (for projecting enemy plans). Reuses world.planets but
    overrides player + my_planets/enemy_planets. Uses __dict__ so plan_evaluate
    can store its _v7_14_base_timelines cache here too."""

    def __init__(self, world, new_player):
        self.player = new_player
        self.planets = world.planets
        self.fleets = world.fleets
        self.planet_by_id = world.planet_by_id
        self.initial_by_id = world.initial_by_id
        self.ang_vel = world.ang_vel
        self.remaining_steps = world.remaining_steps
        self.remaining_overage = getattr(world, 'remaining_overage', 60.0)
        self.step = world.step
        self.comets = getattr(world, 'comets', [])
        self.comet_ids = getattr(world, 'comet_ids', set())
        self.my_planets    = [p for p in world.planets if p.owner == new_player]
        self.enemy_planets = [p for p in world.planets
                                if p.owner not in (-1, new_player)]
        self.neutral_planets = [p for p in world.planets if p.owner == -1]


def predict_enemy_plan(world, enemy_slot, ledger,
                        depth=2, width=4, deadline=None):
    """v7.15 IBR K=1: predict enemy_slot's best plan via shallow plan_beam
    from their POV. Returns list of (target_id, cap_t_int_relative, fleet,
    enemy_slot) for use as virtual arrivals in our augmented ledger.

    Cheap by design (depth=2, width=4) â€” captures the IMMEDIATE threat without
    blowing the budget. plan_evaluate's keep_needed reservation falls back to
    per-call computation (no base_timelines cache for mirror world).
    """
    mw = _MirrorWorld(world, enemy_slot)
    if not mw.my_planets:
        return []

    best = plan_beam_search(mw, ledger=ledger, depth=depth,
                              beam_width=width, deadline=deadline)
    if best is None or not best.get("moves"):
        return []
    out = []
    for m in best["moves"]:
        cap_t_int = int(math.ceil(m["cap_t"]))
        out.append({
            "src_id":     int(m["src_id"]),
            "tgt_id":     int(m["tgt_id"]),
            "t_launch":   int(m["t_launch"]),
            "cap_t":      cap_t_int,
            "fleet":      int(m["fleet"]),
            "enemy_slot": enemy_slot,
        })
    return out


def best_immediate_per_source(world, ledger, exclude_sources=None,
                                exclude_targets=None,
                                avail_now=None):
    """For each our planet NOT in exclude_sources, find the best IMMEDIATE
    (t_launch=0) capture from a single-commit plan. Returns list of move dicts
    sorted by V descending.

    Args:
        exclude_sources: set of source pids to skip
        exclude_targets: set of target pids to skip (already committed)
        avail_now: dict pid -> available ships override (e.g., after defense
                   reservation; defaults to planet.ships)
    """
    exclude_sources = exclude_sources or set()
    exclude_targets = exclude_targets or set()
    player = world.player

    targets = [t for t in world.planets if t.owner != player
                 and t.id not in exclude_targets]
    if not targets:
        return []

    enemy_earliest = {t.id: enemy_earliest_capture(t, world) for t in targets}

    results = []
    for src in world.my_planets:
        if src.id in exclude_sources:
            continue
        src_ships = int(avail_now.get(src.id, src.ships)) if avail_now else int(src.ships)
        if src_ships < 2:
            continue
        # Try each target with this single source (t_launch=0 only)
        for tgt in targets:
            if tgt.id == src.id:
                continue
            res = plan_evaluate(
                [(src.id, tgt.id)], world, ledger,
                enemy_earliest=enemy_earliest,
            )
            if res is None or not res["moves"]:
                continue
            commit = res["moves"][0]
            if commit["t_launch"] != 0:
                continue
            # Make sure we have enough ships in avail_now
            if int(commit["fleet"]) > src_ships:
                continue
            results.append({
                "V":       res["V"],
                "src_id":  src.id,
                "tgt_id":  tgt.id,
                "fleet":   int(commit["fleet"]),
                "cap_t":   commit["cap_t"],
                "production": int(tgt.production),
            })

    results.sort(key=lambda r: -r["V"])
    # Dedupe by source: at most one launch per source per turn (source drains)
    seen_src = set()
    out = []
    for r in results:
        if r["src_id"] in seen_src:
            continue
        seen_src.add(r["src_id"])
        out.append(r)
    return out


# â”€â”€ v51: True Simultaneous Assignment Search â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

def _greedy_simul(simul_srcs, top_tgts, world, ledger, enemy_earliest, deadline):
    """Greedy simultaneous assignment: add sources one at a time by marginal V.
    Used when product space is too large (N_src > SIMUL_MAX_SRC or combos > limit).
    """
    current_pairs: list = []
    current_res = None
    used_tgts: set = set()

    for src_id in simul_srcs:
        if deadline is not None and time.perf_counter() >= deadline:
            break
        best_marginal_res = current_res
        best_marginal_pairs = current_pairs

        for tgt_id in top_tgts.get(src_id, []):
            if tgt_id in used_tgts:
                continue
            trial = current_pairs + [(src_id, tgt_id)]
            res = plan_evaluate(trial, world, ledger, enemy_earliest=enemy_earliest)
            if res is None:
                continue
            if best_marginal_res is None or res["V"] > best_marginal_res["V"]:
                best_marginal_res = res
                best_marginal_pairs = trial

        if best_marginal_pairs is not current_pairs:
            current_pairs = best_marginal_pairs
            current_res = best_marginal_res
            if current_pairs:
                used_tgts.add(current_pairs[-1][1])

    return current_res


def _greedy_full_scan(active_src_ids, all_target_ids, world, ledger,
                      enemy_earliest, deadline):
    """Width-1 greedy sequential plan: iteratively commit the globally best (src,tgt) pair.

    Unlike product-space (limited to top-K per source), this evaluates ALL targets
    at each step. Sequential commitment naturally avoids swarms: once source 1 is
    committed to planet 4, step 2 correctly values planet 12 > swarm on planet 4.

    CRITICAL: plan_best_launch fires ALL available ships from each source. After the
    first commit, leftover=0 and subsequent commits from the same source require
    production accumulation (t_launch>0). These are NOT fired in the current turn
    (main.py only fires t_launch=0 moves). We skip t_launch>0 extensions and mark
    sources as exhausted to avoid phantom V inflation.

    Cost: N_src Ã— N_tgt Ã— plan_evaluate per round, up to N_src rounds.
      â‰ˆ 4 rounds Ã— (4 src Ã— 15 tgt) Ã— 1ms = 240ms â†’ budget-bounded to 3 rounds.
    """
    current_pairs: list = []
    current_res = None
    committed_srcs: set = set()  # sources already assigned (one target per source)

    while deadline is None or time.perf_counter() < deadline:
        best_ext_res = current_res
        best_ext_pair = None
        for src_id in active_src_ids:
            if src_id in committed_srcs:
                continue  # each source gets at most one target per plan call
            if deadline is not None and time.perf_counter() >= deadline:
                break
            for tgt_id in all_target_ids:
                if tgt_id == src_id:
                    continue
                trial = current_pairs + [(src_id, tgt_id)]
                res = plan_evaluate(trial, world, ledger,
                                    enemy_earliest=enemy_earliest)
                if res is None:
                    continue
                if best_ext_res is None or res["V"] > best_ext_res["V"]:
                    best_ext_res = res
                    best_ext_pair = (src_id, tgt_id)
        if best_ext_pair is None:
            break
        committed_srcs.add(best_ext_pair[0])  # one target per source
        current_pairs.append(best_ext_pair)
        current_res = best_ext_res

    return current_res


def _chain_extend(base_res, world, ledger, enemy_earliest, depth, deadline):
    """Extend a simultaneous plan with `depth` additional sequential captures.
    Each depth level finds the single best extension (greedy, one pair per level).
    """
    if not base_res or not base_res.get("moves"):
        return base_res

    player = world.player
    all_targets = [p for p in world.planets if p.owner != player]
    base_pairs = list(base_res.get("plan_pairs") or
                      [(m["src_id"], m["tgt_id"]) for m in base_res["moves"]])

    best = base_res
    current_pairs = list(base_pairs)

    for _ in range(depth):
        if deadline is not None and time.perf_counter() >= deadline:
            break

        # Find the single best extension for this depth level.
        best_ext_res = best
        best_ext_pairs = current_pairs

        # Sources: original sources + planets captured in current plan
        all_srcs = {m["src_id"] for m in best["moves"]} | \
                   {m["tgt_id"] for m in best["moves"]}

        for src_id in all_srcs:
            if deadline is not None and time.perf_counter() >= deadline:
                break
            for tgt in all_targets:
                if tgt.id == src_id:
                    continue
                extended = current_pairs + [(src_id, tgt.id)]
                res = plan_evaluate(extended, world, ledger,
                                     enemy_earliest=enemy_earliest)
                if res is None:
                    continue
                if res["V"] > best_ext_res["V"]:
                    best_ext_res = res
                    best_ext_pairs = extended

        if best_ext_pairs is current_pairs:
            break  # no improvement found
        best = best_ext_res
        current_pairs = best_ext_pairs

    return best


def _enemy_best_response(world, our_moves, enemy_slot, ledger, deadline,
                          depth=2, width=3):
    """v55: compute enemy_slot's best-response plan to our committed moves.

    Injects our plan's fleets into a mirror ledger so the enemy planner sees
    our incoming fleets and plans AROUND them, then runs a shallow beam from
    the enemy's POV. Returns a list of projection dicts (predict_enemy_plan
    format) suitable for assignment to world._v7_30_enemy_projections.

    This is the "min" half of the 2-ply minimax: given our plan P, what does
    the enemy do? v54 used a static projection computed before P was chosen;
    v55 recomputes it as a genuine reaction to P.
    """
    mw = _MirrorWorld(world, enemy_slot)
    if not mw.my_planets:
        return []
    ledger_mirror = dict(ledger)
    for mv in our_moves:
        tgt = mv["tgt_id"]
        eta = int(math.ceil(mv["eta"]))
        fleet = int(mv["fleet"])
        prev = ledger_mirror.get(tgt, [])
        ledger_mirror[tgt] = list(prev) + [(eta, world.player, fleet)]
    try:
        return predict_enemy_plan(mw, enemy_slot, ledger_mirror,
                                   depth=depth, width=width, deadline=deadline)
    except Exception:
        return []


def _adversarial_rerank(candidates, world, ledger, enemy_slot,
                         enemy_earliest, deadline):
    """v55: 2-ply minimax re-ranking of Phase-1 candidate plans.

    v54 picked argmax_P V(P, static_enemy) â€” a one-sided rollout that ignores
    the enemy's reaction. The static enemy projection is computed BEFORE our
    plan is chosen, so V over-credits plans that capture undefended planets
    the enemy will simply recapture (the capture-instability death spiral).

    v55 computes, for each top-M candidate P, the enemy's best response R(P)
    and re-evaluates V(P, R(P)). The winner is argmax_P V(P, R(P)) â€” a true
    2-ply minimax: max over our plans of the value after the enemy's best reply.

    Budget-gated: only candidates evaluated before the deadline compete; if the
    deadline is hit immediately the static Phase-1 best is returned unchanged.
    Returns the winning res dict (re-evaluated against its enemy response).
    """
    if not candidates:
        return None
    saved_proj = world.__dict__.get('_v7_30_enemy_projections')
    best_res = None
    best_v = float('-inf')
    try:
        for cand in candidates:
            moves = cand.get("moves") or []
            if not moves:
                continue
            if deadline is not None and time.perf_counter() >= deadline:
                break
            resp = _enemy_best_response(world, moves, enemy_slot,
                                         ledger, deadline)
            world.__dict__['_v7_30_enemy_projections'] = resp
            try:
                res_adv = plan_evaluate(cand["plan_pairs"], world, ledger,
                                         enemy_earliest=enemy_earliest)
            except Exception:
                res_adv = None
            v_adv = res_adv["V"] if res_adv is not None else cand["V"]
            if v_adv > best_v:
                best_v = v_adv
                best_res = res_adv if res_adv is not None else cand
    finally:
        if saved_proj is not None:
            world.__dict__['_v7_30_enemy_projections'] = saved_proj
        elif '_v7_30_enemy_projections' in world.__dict__:
            del world.__dict__['_v7_30_enemy_projections']
    # Deadline hit before any candidate scored â†’ fall back to static best.
    return best_res if best_res is not None else candidates[0]


def plan_simultaneous_search(world, ledger=None, chain_depth=2, deadline=None,
                              adversarial_m=0, enemy_slot=None):
    """v52: Product-space simultaneous assignment + chain extension (chain_depth=1).

    v52 improvement over v51: chain_depth=1 (default in main.py) extends the
    simultaneous assignment with one sequential capture from each newly-captured
    planet, finding multi-hop chains that product-space misses.

    Algorithm:
      Phase 1 â€” Product-space (same as v51):
        For each source, compute top-K=3 targets (fast V_single estimate).
        Exhaustive product (K+1)^N_src â‰¤ 256 combos; greedy fallback for large maps.
        Includes WAIT option per source; globally optimal within top-K.

      Phase 2 â€” Chain extension (chain_depth iterations, v52 new):
        From the best simultaneous assignment, add sequential captures from
        captured planets. chain_depth=1 adds ~10-30ms per pass, finds
        multi-hop chains like src22â†’tgt0â†’tgt14.

    Returns best plan dict (same format as plan_beam_search) or None.
    """
    if ledger is None:
        ledger = build_arrival_ledger(
            world.fleets, world.planets, world.ang_vel,
            world.comets, world.comet_ids, SIM_HORIZON)

    player = world.player
    all_targets = [p for p in world.planets if p.owner != player]
    if not all_targets:
        return None

    enemy_earliest = {t.id: enemy_earliest_capture(t, world) for t in all_targets}

    # â”€â”€ Active sources with offense budget â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    base_timelines = world.__dict__.get('_v7_14_base_timelines')

    def _kn(p):
        if base_timelines is not None and p.id in base_timelines:
            return base_timelines[p.id]["keep_needed"]
        tl = simulate_planet_timeline(p, ledger.get(p.id, []), player, 100)
        return tl["keep_needed"]

    active_srcs = []
    for p in world.my_planets:
        offs = max(0, int(p.ships) - _kn(p))
        if offs >= 2:
            active_srcs.append((p.id, offs))
    active_srcs.sort(key=lambda x: -x[1])  # most offense first

    if not active_srcs:
        return None

    # â”€â”€ Top-K targets per source (fast V_single estimate) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    K_SIMUL = 4  # top targets per source for initial scoring
    top_tgts: dict = {}

    for src_id, offs in active_srcs:
        src = world.planet_by_id[src_id]
        scored = []
        for tgt in all_targets:
            if tgt.id == src_id:
                continue
            launch = plan_best_launch(
                src_id, src, offs, int(src.production), 0,
                tgt, world, world.remaining_steps,
                ledger=ledger, player=player,
            )
            if launch is None:
                continue
            v = int(tgt.production) * (world.remaining_steps - launch["cap_t"])
            if tgt.owner >= 0 and tgt.owner != player:
                v *= 2  # hostile: mirrors V_state zero-sum semantics
            scored.append((v, tgt.id))
        scored.sort(reverse=True)
        top_tgts[src_id] = [tid for _, tid in scored[:K_SIMUL]]

    # â”€â”€ Phase 1: Product-space or greedy â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    SIMUL_MAX_SRC = 4   # exhaustive up to 4 sources
    K_SIMUL = 3         # bound combos: (3+1)^4 = 256

    n_simul = min(len(active_srcs), SIMUL_MAX_SRC)
    simul_srcs = [s[0] for s in active_srcs[:n_simul]]
    for s in simul_srcs:
        top_tgts[s] = top_tgts.get(s, [])[:K_SIMUL]

    n_combos = 1
    for s in simul_srcs:
        n_combos *= (len(top_tgts.get(s, [])) + 1)  # +1 for WAIT

    # Phase 1 collects ALL feasible candidates (not just the single best) so
    # Phase 1.5 can adversarially re-rank the top-M. v54 kept only argmax V.
    candidates: list = []

    if n_combos <= 512:
        from itertools import product as _iprod
        simul_srcs_rev = list(reversed(simul_srcs))
        options = [[None] + top_tgts.get(s, []) for s in simul_srcs_rev]
        for combo in _iprod(*options):
            if deadline is not None and time.perf_counter() >= deadline:
                break
            pairs = [(s, t) for s, t in zip(simul_srcs_rev, combo) if t is not None]
            if not pairs:
                continue
            res = plan_evaluate(pairs, world, ledger, enemy_earliest=enemy_earliest)
            if res is not None:
                candidates.append(res)
    else:
        gres = _greedy_simul(
            simul_srcs, top_tgts, world, ledger, enemy_earliest, deadline
        )
        if gres is not None:
            candidates.append(gres)

    if not candidates:
        return None
    candidates.sort(key=lambda r: -r["V"])

    # â”€â”€ Phase 1.5: Adversarial 2-ply re-rank of the top-M candidates â”€â”€â”€â”€â”€â”€â”€â”€
    # v55: replace argmax_P V(P, static_enemy) with argmax_P V(P, best_reply(P)).
    if adversarial_m > 0 and enemy_slot is not None:
        best_simul = _adversarial_rerank(
            candidates[:adversarial_m], world, ledger, enemy_slot,
            enemy_earliest, deadline,
        )
    else:
        best_simul = candidates[0]

    # â”€â”€ Phase 2: Chain extension from captured planets â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    if best_simul is not None and chain_depth > 0:
        best_simul = _chain_extend(
            best_simul, world, ledger, enemy_earliest, chain_depth, deadline
        )

    return best_simul


